import jwt
from datetime import timedelta

def generate_jwt(user_id, role):
    payload = {
        'user_id': user_id,
        'role': role,
        'exp': datetime.utcnow() + timedelta(minutes=10)
    }
    return jwt.encode(payload, 'secret', algorithm='HS256')